import{_ as a,o as d,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"阵容搭配指南","description":"","frontmatter":{},"headers":[],"relativePath":"awakeners/team-building.md","filePath":"zh/awakeners/team-building.md","lastUpdated":1775394001000}'),o={name:"awakeners/team-building.md"};function h(l,t,i,n,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="阵容搭配指南" tabindex="-1">阵容搭配指南 <a class="header-anchor" href="#阵容搭配指南" aria-label="Permalink to &quot;阵容搭配指南&quot;">​</a></h1><h2 id="基本原则" tabindex="-1">基本原则 <a class="header-anchor" href="#基本原则" aria-label="Permalink to &quot;基本原则&quot;">​</a></h2><p>忘却前夜的阵容最多包含 <strong>4 名唤醒体</strong>，搭配时需考虑：</p><ol><li><strong>界域协同</strong> - 同界域唤醒体可以更好地配合卡牌效果</li><li><strong>混沌的灵活性</strong> - 混沌界域可以与任意一个其他界域混搭</li><li><strong>定位互补</strong> - 输出 + 防御/辅助的均衡搭配</li><li><strong>卡牌联动</strong> - 不同唤醒体的卡牌之间的配合</li><li><strong>钥令选择</strong> - 根据阵容选择合适的钥令</li></ol><h2 id="界域构筑思路" tabindex="-1">界域构筑思路 <a class="header-anchor" href="#界域构筑思路" aria-label="Permalink to &quot;界域构筑思路&quot;">​</a></h2><h3 id="深海-aequor-体系" tabindex="-1">深海（Aequor）体系 <a class="header-anchor" href="#深海-aequor-体系" aria-label="Permalink to &quot;深海（Aequor）体系&quot;">​</a></h3><ul><li><strong>核心机制</strong>: 召唤触手造成持续伤害</li><li><strong>特点</strong>: 场控能力强，适合持久战</li></ul><h3 id="血肉-caro-体系" tabindex="-1">血肉（Caro）体系 <a class="header-anchor" href="#血肉-caro-体系" aria-label="Permalink to &quot;血肉（Caro）体系&quot;">​</a></h3><ul><li><strong>核心机制</strong>: 生成胚胎卡并通过吞噬/消耗触发效果</li><li><strong>特点</strong>: 爆发伤害高，需要构筑配合</li></ul><h3 id="超维-ultra-体系" tabindex="-1">超维（Ultra）体系 <a class="header-anchor" href="#超维-ultra-体系" aria-label="Permalink to &quot;超维（Ultra）体系&quot;">​</a></h3><ul><li><strong>核心机制</strong>: 打出卡牌获得额外回合</li><li><strong>特点</strong>: 高速连击，动作频率高</li></ul><h3 id="混沌-chaos-混搭" tabindex="-1">混沌（Chaos）混搭 <a class="header-anchor" href="#混沌-chaos-混搭" aria-label="Permalink to &quot;混沌（Chaos）混搭&quot;">​</a></h3><ul><li><strong>核心机制</strong>: 混搭其他界域，加速银钥能量积累</li><li><strong>特点</strong>: 灵活多变，适合搭配不同体系</li></ul><h2 id="推荐阵容" tabindex="-1">推荐阵容 <a class="header-anchor" href="#推荐阵容" aria-label="Permalink to &quot;推荐阵容&quot;">​</a></h2><h3 id="深海队" tabindex="-1">深海队 <a class="header-anchor" href="#深海队" aria-label="Permalink to &quot;深海队&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阵容名</th><th>成员</th><th>备注</th></tr></thead><tbody><tr><td>深海双C队</td><td>图鲁 / 奥瑞塔 / 希莱斯特 / 珊</td><td>标准深海核心阵容</td></tr><tr><td>触手混伤队</td><td>弥利亚姆 / 奥瑞塔 / 凯刻斯 / 墨菲</td><td>触手叠加流</td></tr><tr><td>凯刻斯反击队</td><td>凯刻斯 / 哈姆林 / 戈利亚 / 拉蒙娜</td><td>反击伤害流</td></tr><tr><td>鲨凯队</td><td>戈利亚 / 凯刻斯 / 希莱斯特 / 珊</td><td>防御型深海</td></tr></tbody></table><h3 id="血肉队" tabindex="-1">血肉队 <a class="header-anchor" href="#血肉队" aria-label="Permalink to &quot;血肉队&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阵容名</th><th>成员</th><th>备注</th></tr></thead><tbody><tr><td>尤乌哈希血肉队</td><td>尤乌哈希 / 雷娅 / 艾继丝 / 菲茵特</td><td>核心血肉阵容</td></tr><tr><td>神父队</td><td>萨尔瓦多 / 雷娅 / 艾继丝 / 24或拉蒙娜</td><td>盾反玩法</td></tr><tr><td>24血肉变体</td><td>24 / 希洛或雷娅 / 艾继丝 / 萨尔瓦多</td><td>爆发输出</td></tr></tbody></table><h3 id="超维队" tabindex="-1">超维队 <a class="header-anchor" href="#超维队" aria-label="Permalink to &quot;超维队&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阵容名</th><th>成员</th><th>备注</th></tr></thead><tbody><tr><td>超维毒队（新手推荐）</td><td>旺达 / 诺缔拉 / 艾瑞卡 / 宁菲亚</td><td>新手友好</td></tr><tr><td>超维四小只</td><td>莉兹 / 艾瑞卡 / 奥吉尔 / 朵尔</td><td>全免费角色</td></tr><tr><td>超维双C双盾</td><td>温柯尔 / 艾瑞卡 / 莉兹 / 弹性位</td><td>终局超维</td></tr></tbody></table><h3 id="混沌队" tabindex="-1">混沌队 <a class="header-anchor" href="#混沌队" aria-label="Permalink to &quot;混沌队&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阵容名</th><th>成员</th><th>备注</th></tr></thead><tbody><tr><td>24混沌国家队</td><td>24 / 拉蒙娜 / 奥吉尔 / 莉莉</td><td>顶级混沌阵容</td></tr><tr><td>24深海变体</td><td>24 / 图鲁 / 墨菲 / 珊</td><td>跨界域灵活搭配</td></tr></tbody></table><h2 id="核心联携" tabindex="-1">核心联携 <a class="header-anchor" href="#核心联携" aria-label="Permalink to &quot;核心联携&quot;">​</a></h2><table tabindex="0"><thead><tr><th>联携名</th><th>角色</th><th>机制</th></tr></thead><tbody><tr><td>触手叠加</td><td>图鲁 + 奥瑞塔 + 弥利亚姆</td><td>各自增加触手实例，自动跟随攻击乘法叠加</td></tr><tr><td>胚胎引擎</td><td>雷娅 + 艾继丝</td><td>雷娅吞噬胚胎大量回血，艾继丝生产/管理胚胎</td></tr><tr><td>神父血池循环</td><td>萨尔瓦多 + 雷娅</td><td>雷娅复制神父2费卡，HP吸收→血池饮用→高HP=高伤害</td></tr><tr><td>反击缩放</td><td>凯刻斯 + 诺缔拉</td><td>凯刻斯3觉后防御卡造成反击暴击伤害，诺缔拉填充蓄能条</td></tr><tr><td>24万能适配</td><td>24 + 任意界域</td><td>共鸣随队伍界域变化，始终提供对应增益</td></tr><tr><td>护盾打击</td><td>珊 + 诺缔拉</td><td>珊的护盾型DPS需要诺缔拉的辅助支撑才能运转</td></tr></tbody></table><h2 id="新手优先" tabindex="-1">新手优先 <a class="header-anchor" href="#新手优先" aria-label="Permalink to &quot;新手优先&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优先级</th><th>阵容</th><th>原因</th></tr></thead><tbody><tr><td>1</td><td>深海SR队（凯刻斯/法洛思/奥瑞塔/希莱斯特）</td><td>仅需4张SR即可通关全主线。触手自动跟随操作简单</td></tr><tr><td>2</td><td>超维毒队（莉兹/艾瑞卡/奥吉尔/朵尔）</td><td>全免费/初始角色。叠毒生存即可</td></tr><tr><td>3</td><td>混沌初始四人</td><td>强度尚可，可建立游戏理解</td></tr></tbody></table>',26)])])}const g=a(o,[["render",h]]);export{c as __pageData,g as default};
